#include <iostream>
using namespace std;

void getMinMax(int arr[], int size, int& minVal, int& maxVal) {
  minVal = arr[0];
  maxVal = arr[0];
  for (int i = 1; i < size; i++) {
    if (arr[i] < minVal) minVal = arr[i];
    if (arr[i] > maxVal) maxVal = arr[i];
  }
}

int main() {
  int nums[] = {5, 2, 9, 1, 7};
  int mn, mx;
  getMinMax(nums, 5, mn, mx);
  cout << "Min: " << mn << ", Max: " << mx << endl;
  return 0;
}
